query:
-- إعادة تعيين تواريخ المخيمات: 2 نشطة، 2 منتهية
UPDATE camps SET endDate = '2026-02-25' WHERE id IN (2, 3);
UPDATE camps SET endDate = '2026-01-15' WHERE id IN (1, 4);

SELECT id, name, DATE_FORMAT(endDate, '%Y-%m-%d') as endDate, 
       CASE WHEN endDate >= NOW() THEN 'نشط' ELSE 'منتهي' END as status
FROM camps
ORDER BY endDate DESC;

